// VALIDACIÓN DE FORMATO DE ENTRADA - subflujo-disponibilidad

const input = $input.first().json;

// Extraer datos
const fecha_cita = input.fecha_cita;
const hora_cita = input.hora_cita;
const taller_cita = input.taller_cita;

// VALIDACIONES
const errores = [];

// 1. VALIDAR FECHA (YYYY-MM-DD)
const regexFecha = /^\d{4}-\d{2}-\d{2}$/;
if (!fecha_cita || !regexFecha.test(fecha_cita)) {
  errores.push(`Fecha inválida: "${fecha_cita}". Formato requerido: YYYY-MM-DD (ej: 2025-04-30)`);
}

// VALIDAR DÍA DE SEMANA Y FERIADOS
if (fecha_cita && regexFecha.test(fecha_cita)) {
  const [anio, mes, dia] = fecha_cita.split('-').map(Number);
  const fechaObj = new Date(anio, mes - 1, dia);
  const diaSemana = fechaObj.getDay();

  const feriados = [
    "2025-01-01","2025-02-12","2025-02-13","2025-03-24",
    "2025-04-02","2025-04-18","2025-05-01","2025-05-25",
    "2025-06-20","2025-07-09","2025-08-17","2025-10-12",
    "2025-11-20","2025-12-08","2025-12-25",
    "2026-01-01","2026-03-24","2026-04-02","2026-05-01",
    "2026-05-25","2026-06-20","2026-07-09","2026-08-17",
    "2026-10-12","2026-11-20","2026-12-08","2026-12-25"
  ];

  let motivoNoHabil = null;
  if (diaSemana === 0) motivoNoHabil = "domingo";
  else if (diaSemana === 6) motivoNoHabil = "sábado";
  else if (feriados.includes(fecha_cita)) motivoNoHabil = "feriado_nacional";

  if (motivoNoHabil) {
    const NOMBRES_DIA = ["domingo","lunes","martes","miércoles","jueves","viernes","sábado"];
    const _dia_semana = NOMBRES_DIA[diaSemana];
    const _fecha_legible = `${_dia_semana} ${String(dia).padStart(2,'0')}/${String(mes).padStart(2,'0')}/${anio}`;
    return [{
      json: {
        success: true,
        disponible: false,
        es_horario_valido: false,
        fecha: fecha_cita,
        dia_semana: _dia_semana,        
        fecha_legible: _fecha_legible,  
        taller: taller_cita,
        turnos_disponibles: [],
        turnos_ocupados: [],
        total_turnos_disponibles: 0,
        motivo: motivoNoHabil,
        mensaje: `El ${_fecha_legible} no es día hábil (${motivoNoHabil}). El taller no atiende.`
      }
    }];
  }

}

// VALIDAR ANTICIPACIÓN (no hoy, no pasado) — hora de Argentina, sin importar TZ del VPS
if (fecha_cita && regexFecha.test(fecha_cita)) {
  // "hoy" en Argentina como "YYYY-MM-DD" (en-CA da formato ISO)
  const hoyAR = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Argentina/Salta' });
  if (fecha_cita <= hoyAR) {                       // comparación lexicográfica de ISO = segura
    const [a, m, d] = fecha_cita.split('-').map(Number);
    const NOMBRES_DIA = ["domingo","lunes","martes","miércoles","jueves","viernes","sábado"];
    const _ds = NOMBRES_DIA[new Date(a, m - 1, d).getDay()];
    const _fl = `${_ds} ${String(d).padStart(2,'0')}/${String(m).padStart(2,'0')}/${a}`;
    return [{ json: {
      success: true,
      disponible: false,
      es_horario_valido: false,
      fecha: fecha_cita, dia_semana: _ds, fecha_legible: _fl, taller: taller_cita,
      turnos_disponibles: [], turnos_ocupados: [], total_turnos_disponibles: 0,
      motivo: "anticipacion_insuficiente",
      mensaje: `El ${_fl} no se puede agendar: las citas se piden desde mañana en adelante (mínimo 24 hs).`
    }}];
  }
}

// 2. VALIDAR HORA (HH:MM)
const regexHora = /^\d{2}:\d{2}$/;
if (!hora_cita || !regexHora.test(hora_cita)) {
  errores.push(`Hora inválida: "${hora_cita}". Formato requerido: HH:MM (ej: 10:15)`);
}

// Validar que sea uno de los 10 turnos válidos
const turnosValidos = [
  "08:00", "08:15", "08:30", "08:45",
  "09:00", "09:15", "09:30", "09:45",
  "10:00", "10:15"
];
if (hora_cita && !turnosValidos.includes(hora_cita)) {
  errores.push(`Hora no permitida: "${hora_cita}". Solo se aceptan turnos: ${turnosValidos.join(', ')}`);
}

// 3. VALIDAR TALLER (valores exactos)
const talleresValidos = [
  "Nissan - Tucuman",
  "Nissan - Santiago del Estero"
];
if (!taller_cita || !talleresValidos.includes(taller_cita)) {
  errores.push(`Taller inválido: "${taller_cita}". Valores permitidos: "${talleresValidos[0]}" o "${talleresValidos[1]}"`);
}

// SI HAY ERRORES: Detener ejecución y retornar error
if (errores.length > 0) {
  return [{
    json: {
      success: false,
      error: "VALIDACIÓN_FORMATO_FALLIDA",
      errores: errores,
      datos_recibidos: {
        fecha_cita,
        hora_cita,
        taller_cita
      }
    }
  }];
}

// SI TODO OK: Pasar datos validados
return [{
  json: {
    success: true,
    fecha_cita,
    hora_cita,
    taller_cita
  }
}];

// PROCESAR DISPONIBILIDAD Y GENERAR RESPUESTA

// Datos de entrada
const trigger = $('trigger-disponibilidad').first().json;
const httpResponse = $input.first().json;

const fechaSolicitada = trigger.fecha_cita;
const horaSolicitada = trigger.hora_cita;
const tallerSolicitado = trigger.taller_cita;

// --- Día de la semana calculado en CÓDIGO (jamás lo deduce el LLM) ---
const NOMBRES_DIA = ["domingo","lunes","martes","miércoles","jueves","viernes","sábado"];
const [_anio, _mes, _dia] = fechaSolicitada.split('-').map(Number);
const _fechaObj = new Date(_anio, _mes - 1, _dia);      // local: getDay() sin offset
const dia_semana = NOMBRES_DIA[_fechaObj.getDay()];
const _dd = String(_dia).padStart(2, '0');
const _mm = String(_mes).padStart(2, '0');
const fecha_legible = `${dia_semana} ${_dd}/${_mm}/${_anio}`;

// --- GUARD: día no hábil / feriado / sin anticipación (MANDA sobre el CRM) ---
const FERIADOS = [
  "2025-01-01","2025-02-12","2025-02-13","2025-03-24",
  "2025-04-02","2025-04-18","2025-05-01","2025-05-25",
  "2025-06-20","2025-07-09","2025-08-17","2025-10-12",
  "2025-11-20","2025-12-08","2025-12-25",
  "2026-01-01","2026-03-24","2026-04-02","2026-05-01",
  "2026-05-25","2026-06-20","2026-07-09","2026-08-17",
  "2026-10-12","2026-11-20","2026-12-08","2026-12-25"
];
const _diaNum = _fechaObj.getDay();
const _hoyAR = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Argentina/Salta' });

let _motivoNoHabil = null;
if (_diaNum === 0) _motivoNoHabil = "domingo";
else if (_diaNum === 6) _motivoNoHabil = "sábado";
else if (FERIADOS.includes(fechaSolicitada)) _motivoNoHabil = "feriado_nacional";
else if (fechaSolicitada <= _hoyAR) _motivoNoHabil = "anticipacion_insuficiente";

if (_motivoNoHabil) {
  const _msg = _motivoNoHabil === "anticipacion_insuficiente"
    ? `El ${fecha_legible} no se puede agendar: las citas se piden desde mañana en adelante (mínimo 24 hs).`
    : `El ${fecha_legible} no es día hábil (${_motivoNoHabil}). El taller no atiende.`;
  return [{ json: {
    success: true,
    disponible: false,
    es_horario_valido: false,
    fecha: fechaSolicitada,
    dia_semana: dia_semana,
    fecha_legible: fecha_legible,
    taller: tallerSolicitado,
    turnos_disponibles: [],
    turnos_ocupados: [],
    total_turnos_disponibles: 0,
    motivo: _motivoNoHabil,
    mensaje: _msg
  }}];
}

// Todos los turnos posibles del día (cada 15 min de 08:00 a 10:15)
const TODOS_LOS_TURNOS = [
  "08:00", "08:15", "08:30", "08:45",
  "09:00", "09:15", "09:30", "09:45",
  "10:00", "10:15"
];

// Extraer citas del día desde la respuesta del CRM
const citasDelDia = httpResponse.InternalObject || [];

// Obtener solo las horas ocupadas (pueden haber duplicados)
const horasOcupadas = citasDelDia.map(cita => cita.HORA);
const horasOcupadasUnicas = [...new Set(horasOcupadas)]; // eliminar duplicados

// Calcular turnos disponibles
const turnosDisponibles = TODOS_LOS_TURNOS.filter(
  turno => !horasOcupadasUnicas.includes(turno)
);

// Verificar si el horario solicitado está disponible
const estaDisponible = !horasOcupadasUnicas.includes(horaSolicitada);

// Validar si la hora solicitada es válida
const esHoraValida = TODOS_LOS_TURNOS.includes(horaSolicitada);

// Generar mensaje descriptivo
let mensaje;
if (!esHoraValida) {
  mensaje = `La hora ${horaSolicitada} no es un turno válido. Turnos permitidos cada 15 min de 08:00 a 10:15.`;
} else if (estaDisponible) {
  mensaje = `✅ El horario ${horaSolicitada} está DISPONIBLE para el ${fechaSolicitada} en ${tallerSolicitado}.`;
} else {
  const alternativas = turnosDisponibles.slice(0, 3).join(", "); // primeras 3 opciones
  mensaje = `❌ El horario ${horaSolicitada} está OCUPADO. Horarios disponibles: ${alternativas}${turnosDisponibles.length > 3 ? '...' : ''}`;
}

// Preparar respuesta estructurada
const respuesta = {
  success: true,
  horario_solicitado: horaSolicitada,
  disponible: estaDisponible && esHoraValida,
  es_horario_valido: esHoraValida,
  fecha: fechaSolicitada,
  dia_semana: dia_semana,       
  fecha_legible: fecha_legible, 
  taller: tallerSolicitado,
  turnos_ocupados: horasOcupadasUnicas.sort(), // ordenados
  turnos_disponibles: turnosDisponibles,
  total_citas_dia: citasDelDia.length,
  total_turnos_ocupados: horasOcupadasUnicas.length,
  total_turnos_disponibles: turnosDisponibles.length,
  mensaje: mensaje,
  // Info adicional útil para el agente
  proximos_disponibles: turnosDisponibles.slice(0, 5), // top 5
  todas_las_citas: citasDelDia.map(c => ({
    hora: c.HORA,
    servicio: c.SERVICIO,
    doc_id: c.DOC_ID
  }))
};

return [{ json: respuesta }];

// En el nodo "salida_con_error" (Code node)
const errores = $input.first().json.errores || ["Error de validación"];

return [{
  json: {
    success: false,
    error: "VALIDACION_FALLIDA",
    errores: errores,
    disponible: false,
    mensaje: errores.join(", ")
  }
}];

